sql:
SELECT COUNT(*) AS puzzle_count
FROM puzzles
WHERE creator_id = (SELECT participant_id FROM participants WHERE name = 'John Doe');

SELECT COUNT(DISTINCT pa.participant_id)
FROM puzzle_attempts pa
WHERE pa.puzzle_id = 1 AND pa.end_time IS NOT NULL;

external_knowledge:
Active participants: Participants whose status is marked as 'active';
Time spent on puzzles: The difference between the end time and the start time for each puzzle attempt;
Last week: Refers to the period of the last 7 days;
Reward: Indicates that the participant has received some form of recognition or reward, listed in the 'rewards' table.

sql:
SELECT *
FROM puzzles
ORDER BY unlock_time DESC;

SELECT COUNT(*) AS total_participants_with_bio
FROM participant_profiles
WHERE bio IS NOT NULL;

SELECT participant_id, name, email, registration_time, birthdate, location
FROM participants
WHERE participant_id NOT IN (
    SELECT participant_id 
    FROM puzzle_attempts
);

SELECT puzzle_id, average_solve_time
FROM puzzle_statistics
WHERE average_solve_time > 120;

SELECT puzzle_id, rating, review_status 
FROM puzzle_reviews 
WHERE review_status = 'pending';

SELECT status, COUNT(*) AS status_count
FROM participants
GROUP BY status;

SELECT participant_id
FROM participant_statistics
WHERE total_puzzles_solved < 100;
